package net.unit8.souther.runtime;

import java.util.ArrayList;
import java.util.List;
import java.util.Map;

/** Map helpers the generated bytecode calls (spec 18.5). A key is a String or a String-backed
 *  newtype value (ADR-0040), compared by value equality (ADR-0009), so keys are typed {@code Object}
 *  here. A {@code Map} value is a {@link PersistentHashMap} (CHAMP, structural sharing): the building
 *  operations return a fresh map that shares structure with the input in O(log n), never mutating it,
 *  so a {@code groupBy} that grows a map is O(n log n) rather than the O(n²) a whole-map copy costs.
 *  Iteration order is a deterministic, implementation-defined hash order (not insertion order), stable
 *  for the same key set so boundary encoding stays reproducible. Inputs may be any {@code java.util.Map}
 *  (a decoded map comes from Raoh as a {@code LinkedHashMap}), so builders normalize through
 *  {@link PersistentHashMap#from}. */
public final class Maps {

    private Maps() {}

    /** The empty map. Its key and value types are fixed by context (the {@code Map.empty} built-in),
     *  like the empty list; at runtime it is element-agnostic. */
    public static Map<Object, ?> empty() {
        return PersistentHashMap.<Object, Object>empty();
    }

    /** A one-entry map. */
    public static <K, V> Map<K, V> singleton(K key, V value) {
        return PersistentHashMap.<K, V>empty().assoc(key, value);
    }

    /** {@code m} with {@code key} set to {@code value} (added, or overwriting an existing entry). */
    public static <K, V> Map<K, V> insert(K key, V value, Map<K, V> m) {
        return PersistentHashMap.from(m).assoc(key, value);
    }

    /** {@code m} without {@code key}; {@code m} unchanged when the key is absent. The {@code containsKey}
     *  probe is worth the extra lookup: when the key is absent it returns the original map untouched,
     *  which avoids normalizing a still-JDK input map (a just-decoded {@code LinkedHashMap}) into a
     *  {@code PersistentHashMap} for a no-op removal. */
    public static <K, V> Map<K, V> remove(K key, Map<K, V> m) {
        if (!m.containsKey(key)) {
            return m;
        }
        return PersistentHashMap.from(m).without(key);
    }

    public static boolean isEmpty(Map<?, ?> m) {
        return m.isEmpty();
    }

    public static long size(Map<?, ?> m) {
        return m.size();
    }

    /** The entries as a list of {@code (key, value)} tuples, each an {@code Object[]} (ADR-0036),
     *  in the map's iteration order. */
    public static <K, V> List<Object[]> toList(Map<K, V> m) {
        List<Object[]> out = new ArrayList<>(m.size());
        for (Map.Entry<K, V> e : m.entrySet()) {
            out.add(new Object[]{e.getKey(), e.getValue()});
        }
        return PersistentVector.from(out);
    }

    /** A map from a list of {@code (key, value)} tuples; a later entry overwrites an earlier one
     *  with the same key. */
    @SuppressWarnings("unchecked")
    public static <K, V> Map<K, V> fromList(List<Object[]> entries) {
        PersistentHashMap<K, V> out = PersistentHashMap.empty();
        for (Object[] e : entries) {
            out = out.assoc((K) e[0], (V) e[1]);
        }
        return out;
    }

    /** {@code Some(value)} when {@code key} is present, else {@code None}. A Souther map never stores a
     *  null value — absence is {@code None}, not a null entry — so a single lookup distinguishes the
     *  two, no {@code containsKey} probe before {@code get}. */
    public static <V> Option<V> get(Map<?, V> map, Object key) {
        V value = map.get(key);
        return value != null ? Option.some(value) : Option.none();
    }

    public static boolean containsKey(Map<?, ?> map, Object key) {
        return map.containsKey(key);
    }

    public static List<Object> keys(Map<?, ?> map) {
        return PersistentVector.from(map.keySet());
    }

    public static <V> List<V> values(Map<?, V> map) {
        return PersistentVector.from(map.values());
    }

    /** {@code m} with every key rewritten by {@code keyFn}, values unchanged.
     *  The encoder uses it to render a {@code Map<商品ID, V>}'s keys bare (each key's {@code value})
     *  before the boundary map encoder writes a {@code String}-keyed object. */
    public static <K, V> Map<Object, V> mapKeys(Map<K, V> m, java.util.function.Function<K, ?> keyFn) {
        PersistentHashMap<Object, V> out = PersistentHashMap.empty();
        for (Map.Entry<K, V> e : m.entrySet()) {
            out = out.assoc(keyFn.apply(e.getKey()), e.getValue());
        }
        return out;
    }
}
